var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......이런 곳에서 뭘 하고 있는 거지, 비숍?","JPN":"……こんなところで何をしている？　ビショップ。","ENG":"What are you doing in a place like this, Bishop?","TWN":"……妳在這種地方做什麼，大主教？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"내가 기함에서 멀리 떨어지지 말라고 했을 텐데.","JPN":"旗艦からあまり離れるなと言ったはずだ。","ENG":"I told you not to stay too far from the flagship.","TWN":"我說過不可以跑到離旗艦上太遠的地方的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"라디오...... 노래를 듣고 있다.","JPN":"ラジオ……歌を聞いている。","ENG":"I'm listening to a song from the radio...","TWN":"我在聽廣播……的歌曲。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"라디오......?","JPN":"ラジオ……？","ENG":"The radio?","TWN":"廣播……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"이 근처는 뉴 오하이오의 스텔스 필드 영향권 안이라서 외부 전파 따윈 모두 차단될 텐데?","JPN":"この辺りはニューオハイオのステルスフィールドに含まれているから、\\n外部の電波なんて一切入らないと思うが？","ENG":"We're inside the stealth field of the New Ohio and any airwaves from outside are supposed to be blocked.","TWN":"這附近都在新俄亥俄的隱形場域影響範圍內，外部電波什麼的應該都被隔斷了才對啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......아니, 그보다 애초에 이 이면세계 깊은 곳에서 무슨 라디오 따위가 나온다는 거지?","JPN":"……いや、それよりも、そもそもこの裏世界の奥地でラジオなんか聞けるはずがない。","ENG":"No, before that, how is that radio working in the depths of the Counterside?","TWN":"……不，還是說原來異界的深處有什麼廣播嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......여긴 스텔스 필드의 끝자락이다.","JPN":"……ここはステルスフィールドの端。","ENG":"This is the farthest end of the stealth field.","TWN":"……這裡是隱形場域的邊界。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"필드 중심부와는 달리 외부 전파가 완전히 차단되지는 않아.","JPN":"フィールド中心部とは違って、外部の電波が完全に遮断されることはない。","ENG":"Unlike in the center, there's a weak flow of radio waves here.","TWN":"和隱形場域的中心不一樣，外部電波不會被完全遮斷。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"잡음이 많긴 하지만...... 들을 정도는 되지.","JPN":"ノイズも多いが……聞けないことはない。","ENG":"It has a lot of noise to it, but it's bearable.","TWN":"雖然雜音很多……但還是能夠聽得到。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그리고 두 번째 질문에 대한 답은...... 나도 모른다.","JPN":"それから、二つ目の疑問については……私もなぜかはわからない。","ENG":"And for the second question... I have no idea.","TWN":"至於第二個問題……我也不知道。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"오래된 라디오 주파수 같은데......","JPN":"古いラジオ局の周波数みたいだが……","ENG":"It seems to be an old radio channel.","TWN":"那是很久以前的無線頻率……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"며칠 전부터 같은 노래가 계속 반복되고 있을 뿐이다.","JPN":"数日前から同じ歌が繰り返し流れている。","ENG":"It's been repeating the same song over and over again for a few days.","TWN":"從幾天前就一直在反復播放著同一首歌。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"......신기하군.","JPN":"……不思議だな。","ENG":"That's weird.","TWN":"……真是不可思議呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_121010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"저 멀리 어딘가에 버려진 라디오 방송국이라도 있다는 건가?","JPN":"どこか遠くに、捨てられたラジオ局でもあるとでも？","ENG":"Could there be an abandoned radio station somewhere far from here?","TWN":"難道遠方的某處有廢棄的廣播電臺嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_121010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"하긴, 이면세계에서 이해 못할 일이 벌어지는 게 특별한 일은 아니지.","JPN":"まあ、裏世界では理解不能なことが起きてもおかしくないからな。","ENG":"Well, I guess nothing's too crazy here in the Counterside.","TWN":"不過說起來，在異界裡發生無法理解的現象，也不是什麼特別的事情就是了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_121010","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"그나저나 음악 감상 같은 취미가 있는 줄은 몰랐군, 비숍.","JPN":"とにかく、音楽鑑賞のような趣味があるとは知らなかったな、ビショップ。","ENG":"But I never took you for a music lover, Bishop.","TWN":"不過沒想到妳還有欣賞音樂的愛好呢，主教。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"무슨 노래를 듣고 있는 건지 궁금한데.","JPN":"どんな曲か気になるな。","ENG":"I'm actually curious what song you're listening to.","TWN":"讓人不禁好奇妳在聽什麼呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};